+fn parse_color_slot(field: &'static str, value: &str) -> Result<Color, ThemeConfigError> {
+    parse_hex_color(value).ok_or_else(|| ThemeConfigError::InvalidColorValue {
+        field,
+        value: value.trim().to_string(),
